   259→// Auto-complete competitions that have ended and mark winners
   260→async function autoCompleteCompetitions() {
   261→  try {
   262→    const { competitions, competitionEntries } = await import('../shared/schema');
   263→    const { db } = await import('./db');
   264→    const { eq, and, lte, desc, ne } = await import('drizzle-orm');
   265→    
   266→    // Find competitions that have ended but not yet completed
   267→    // Uses status != 'completed' to prevent reprocessing
   268→    const endedCompetitions = await db.select().from(competitions)
   269→      .where(and(
   270→        lte(competitions.endDate, new Date()),
   271→        ne(competitions.status, 'completed')
   272→      ));
