   274→    for (const comp of endedCompetitions) {
   275→      // Get top voted entry
   276→      const [topEntry] = await db.select().from(competitionEntries)
   277→        .where(eq(competitionEntries.competitionId, comp.id))
   278→        .orderBy(desc(competitionEntries.votes))
   279→        .limit(1);
   280→      
   281→      if (topEntry) {
   282→        // Mark winner and set status to completed
   283→        await db.update(competitions)
   284→          .set({ winnerId: topEntry.userId, status: 'completed', isActive: false })
   285→          .where(eq(competitions.id, comp.id));
   286→        
   287→        await db.update(competitionEntries)
   288→          .set({ isWinner: true, rank: 1 })
   289→          .where(eq(competitionEntries.id, topEntry.id));
   290→        
   291→        console.log(`Competition "${comp.title}" completed. Winner: User ${topEntry.userId}`);
   292→      } else {
   293→        // No entries, mark as completed to prevent reprocessing
   294→        await db.update(competitions)
   295→          .set({ status: 'completed', isActive: false })
   296→          .where(eq(competitions.id, comp.id));
   297→        console.log(`Competition "${comp.title}" completed with no entries.`);
   298→      }
   299→    }
   300→  } catch (error) {
