   332→    
   333→    console.log('✅ Background initialization complete');
   334→  } catch (error: any) {
   335→    console.log('⚠️  Background initialization error (non-fatal):', error.message);
   336→  }
   337→}
   338→
   339→// Start the server
   340→startServer();
