     1→import type { Express, Request, Response } from "express";
     2→import express from "express";
     3→import { promises as fsp, createReadStream, existsSync } from "fs";
     4→import path from "path";
     5→import crypto from "crypto";
     6→import { allowedMediaExtensions } from "./upload";
     7→
     8→const STORAGE_DIR =
     9→  process.env.LOCAL_STORAGE_DIR || path.join(process.cwd(), "uploads-objects");
    10→
    11→const TOKEN_TTL_SECONDS = 60 * 15; // 15 min
    12→
    13→/**
    14→ * Storage backend selection.
    15→ *
    16→ * Defaults to **local/server disk** storage so the app works on any plain
    17→ * server (VPS, bare metal, Docker) with no external dependencies. Uploaded
    18→ * files are written under LOCAL_STORAGE_DIR (or ./uploads-objects) and served
    19→ * from the /objects/* route.
    20→ *
    21→ * Replit Object Storage is opt-in via STORAGE_MODE=replit and only works when
    22→ * running on Replit infrastructure, which provides the storage sidecar at
    23→ * 127.0.0.1:1106. On a normal server that sidecar does not exist, so trying to
    24→ * use it would make every upload fail with a 500.
    25→ */
    26→export function isLocalStorageMode(): boolean {
    27→  const mode = (process.env.STORAGE_MODE || "").trim().toLowerCase();
    28→  if (mode === "replit" || mode === "object" || mode === "gcs") return false;
    29→  if (mode === "local" || mode === "disk" || mode === "server") return true;
    30→  // Default: local/server disk storage.
    31→  return true;
    32→}
    33→
    34→function getSigningSecret(): string {
    35→  const s = process.env.JWT_SECRET;
    36→  if (!s) throw new Error("JWT_SECRET required for local upload tokens");
    37→  return s;
    38→}
    39→
    40→function signToken(payload: { p: string; e: number }): string {
    41→  const body = Buffer.from(JSON.stringify(payload)).toString("base64url");
    42→  const sig = crypto
    43→    .createHmac("sha256", getSigningSecret())
    44→    .update(body)
    45→    .digest("base64url");
    46→  return `${body}.${sig}`;
    47→}
    48→
    49→function verifyToken(token: string): string | null {
    50→  const [body, sig] = token.split(".");
    51→  if (!body || !sig) return null;
    52→  const expected = crypto
    53→    .createHmac("sha256", getSigningSecret())
    54→    .update(body)
    55→    .digest("base64url");
    56→  if (
    57→    sig.length !== expected.length ||
    58→    !crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))
    59→  )
    60→    return null;
    61→  try {
    62→    const { p, e } = JSON.parse(Buffer.from(body, "base64url").toString());
    63→    if (typeof p !== "string" || typeof e !== "number") return null;
    64→    if (Math.floor(Date.now() / 1000) > e) return null;
    65→    if (!p.startsWith("/objects/") || p.includes("..")) return null;
    66→    return p;
    67→  } catch {
    68→    return null;
    69→  }
    70→}
    71→
    72→function objectPathToDiskPath(objectPath: string): string {
    73→  // /objects/foo/bar.png  →  <STORAGE_DIR>/foo/bar.png
    74→  const rel = objectPath.replace(/^\/objects\//, "");
    75→  const abs = path.join(STORAGE_DIR, rel);
    76→  const root = path.resolve(STORAGE_DIR);
    77→  if (!path.resolve(abs).startsWith(root + path.sep)) {
    78→    throw new Error("Invalid object path");
    79→  }
    80→  return abs;
    81→}
    82→
    83→/** Save a buffer to local storage and return its /objects/... URL. */
    84→export async function saveLocalObject(
    85→  fileBuffer: Buffer,
    86→  originalFilename: string,
    87→  _mimeType: string,
    88→  folder: string = "uploads"
    89→): Promise<string> {
    90→  const ext = path.extname(originalFilename) || "";
    91→  const id = crypto.randomUUID();
    92→  const objectPath = `/objects/${folder}/${id}${ext}`;
    93→  const disk = objectPathToDiskPath(objectPath);
    94→  await fsp.mkdir(path.dirname(disk), { recursive: true });
    95→  await fsp.writeFile(disk, fileBuffer);
    96→  return objectPath;
    97→}
    98→
    99→export function registerLocalObjectStorageRoutes(app: Express): void {
   100→  // Step 1: client requests an upload URL with metadata
   101→  app.post("/api/uploads/request-url", express.json(), (req, res) => {
   102→    try {
   103→      const { name, contentType } = req.body || {};
   104→      if (!name) return res.status(400).json({ error: "Missing field: name" });
   105→
   106→      const ext = (path.extname(String(name)) || "").toLowerCase();
   107→      if (!allowedMediaExtensions.has(ext)) {
   108→        return res.status(400).json({ error: "Unsupported file type" });
   109→      }
   110→      const objectPath = `/objects/uploads/${crypto.randomUUID()}${ext}`;
   111→      const exp = Math.floor(Date.now() / 1000) + TOKEN_TTL_SECONDS;
   112→      const token = signToken({ p: objectPath, e: exp });
   113→      const proto =
   114→        (req.headers["x-forwarded-proto"] as string) ||
   115→        (req.secure ? "https" : "http");
   116→      const host = req.headers["x-forwarded-host"] || req.headers.host;
   117→      const uploadURL = `${proto}://${host}/api/uploads/put/${token}`;
   118→
   119→      res.json({
   120→        uploadURL,
   121→        objectPath,
   122→        metadata: { name, contentType },
   123→      });
   124→    } catch (err) {
   125→      console.error("[local-storage] request-url error:", err);
   126→      res.status(500).json({ error: "Failed to generate upload URL" });
   127→    }
   128→  });
   129→
   130→  // Step 2: client PUTs the file body to the signed URL
   131→  app.put(
   132→    "/api/uploads/put/:token",
   133→    express.raw({ type: "*/*", limit: "100mb" }),
   134→    async (req: Request, res: Response) => {
   135→      try {
   136→        const objectPath = verifyToken(req.params.token);
   137→        if (!objectPath)
   138→          return res.status(403).json({ error: "Invalid or expired token" });
   139→
   140→        const buf = req.body as Buffer;
   141→        if (!Buffer.isBuffer(buf) || buf.length === 0) {
   142→          return res.status(400).json({ error: "Empty body" });
   143→        }
   144→
   145→        const disk = objectPathToDiskPath(objectPath);
   146→        await fsp.mkdir(path.dirname(disk), { recursive: true });
   147→        await fsp.writeFile(disk, buf);
   148→        res.json({ ok: true, objectPath });
   149→      } catch (err) {
   150→        console.error("[local-storage] put error:", err);
   151→        res.status(500).json({ error: "Failed to save file" });
   152→      }
   153→    }
   154→  );
   155→
   156→  // Step 3: serve uploaded objects
   157→  app.get(/^\/objects\/(.*)/, async (req: Request, res: Response) => {
   158→    try {
   159→      const objectPath = `/objects/${(req.params as any)[0]}`;
